-- Create "invites" table
CREATE TABLE "invites" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "code" uuid NOT NULL, "email" character varying NOT NULL, "user_id" bigint NULL, "status" character varying NOT NULL DEFAULT 'NEW', "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "tenant_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "invites_tenants_invites" FOREIGN KEY ("tenant_id") REFERENCES "tenants" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create index "invite_tenant_id_email" to table: "invites"
CREATE UNIQUE INDEX "invite_tenant_id_email" ON "invites" ("tenant_id", "email");
